INSERT INTO Quotes (QuoteId, Text, Author, IsFavorite, IsCustom, CreatedAt) VALUES
  ('q-seed-001', 'The early morning has gold in its mouth.', 'Benjamin Franklin', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-002', 'Every morning brings new potential, but if you dwell on the misfortunes of the day before, you tend to overlook tremendous opportunities.', 'Harvey Mackay', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-003', 'An early-morning walk is a blessing for the whole day.', 'Henry David Thoreau', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-004', 'The way to get started is to quit talking and begin doing.', 'Walt Disney', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-005', 'It is well to be up before daybreak, for such habits contribute to health, wealth, and wisdom.', 'Aristotle', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-006', 'Morning is an important time of day, because how you spend your morning often tells you what kind of day you are going to have.', 'Lemony Snicket', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-007', 'With the new day comes new strength and new thoughts.', 'Eleanor Roosevelt', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-008', 'The breeze at dawn has secrets to tell you. Do not go back to sleep.', 'Rumi', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-009', 'Each morning we are born again. What we do today is what matters most.', 'Buddha', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-010', 'I wake up every morning and think to myself, how far can I push this company in the next 24 hours.', 'Leah Busque', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-011', 'The secret of getting ahead is getting started.', 'Mark Twain', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-012', 'Lose an hour in the morning and you will spend all day looking for it.', 'Richard Whately', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-013', 'When you arise in the morning, think of what a precious privilege it is to be alive.', 'Marcus Aurelius', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-014', 'Opportunities are like sunrises. If you wait too long, you miss them.', 'William Arthur Ward', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-015', 'Today is a new day. Do not let your history interfere with your destiny.', 'Steve Maraboli', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-016', 'You have got to get up every morning with determination if you are going to go to bed with satisfaction.', 'George Lorimer', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-017', 'Set a goal that makes you want to jump out of bed in the morning.', 'Unknown', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-018', 'The only way to do great work is to love what you do.', 'Steve Jobs', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-019', 'Do not count the days, make the days count.', 'Muhammad Ali', 0, 0, '2026-01-01T00:00:00Z'),
  ('q-seed-020', 'Life is what happens when you are busy making other plans.', 'John Lennon', 0, 0, '2026-01-01T00:00:00Z');
